// Static page → no <script>, no Link header
export default function About() {
  return <h1>About</h1>;
}

// Interactive page → runtime is loaded automatically
export default function Counter() {
  return (
    <body f-client-nav>
      <CounterIsland />
    </body>
  );
}

import { csp } from "@hushkey/howl/middleware";
import { getNonce } from "@hushkey/howl";

app.use(csp());                 // nonce on by default
app.use(csp({ nonce: false })); // legacy: script-src 'self' 'unsafe-inline'

// Read the active nonce in your own middleware
app.use((ctx) => {
  const nonce = getNonce(ctx); // 32-char hex string
  return ctx.next();
});

// client/pages/_app.tsx
export default function App({ Component }: PageProps) {
  return (
    <html>
      <body f-client-nav f-view-transition>
        <Partial name="main">
          <Component />
        </Partial>
      </body>
    </html>
  );
}

/* Animate the whole document */
@keyframes fade-in  { from { opacity: 0 } to { opacity: 1 } }
@keyframes fade-out { from { opacity: 1 } to { opacity: 0 } }

::view-transition-old(root) { animation: fade-out 0.2s ease-in;  }
::view-transition-new(root) { animation: fade-in  0.2s ease-out; }

/* Animate individual elements that should morph across pages */
.sidebar { view-transition-name: sidebar; }
